    def inlet(self, body: dict) -> dict:
        data = {"type": "x_search"}
        if self.valves.enable_image_understanding:
            data["enable_image_understanding"] = True
        if self.valves.enable_video_understanding:
            data["enable_video_understanding"] = True
        if body.get("tools"):
            body["tools"].append(data)
        else:
            body["tools"] = [data]
        return body
